const body = $json.body ?? {};
const command = body.command ?? null;

if (command === 'receipt') {
  const imageUrl = body.receipt?.url;
  const contentType = body.receipt?.contentType ?? '';

  if (!imageUrl) {
    return [{ json: { route: 'invalid', error_code: 'MISSING_RECEIPT_URL', message: 'receipt.url is required for the receipt workflow.' } }];
  }

  if (contentType && !contentType.startsWith('image/')) {
    return [{ json: { route: 'invalid', error_code: 'INVALID_RECEIPT_CONTENT_TYPE', message: 'receipt.contentType must be an image/* mime type.' } }];
  }

  return [{ json: { ...$json, route: 'receipt' } }];
}

if (command === 'out') {
  return [{ json: { ...$json, route: 'outcome' } }];
}

return [{ json: { route: 'invalid', error_code: 'UNSUPPORTED_COMMAND', message: 'Only the receipt and out commands are supported by this webhook path.' } }];

const body = $json.body ?? {};
const submittedAt = body.submittedAt ?? new Date().toISOString();

if ((body.command ?? null) !== 'out') {
  return [{ json: { route: 'respond', status: 'invalid', message: 'Unsupported outcome request.' } }];
}

if (body.mode === 'finalize') {
  const draft = body.outcome?.draft ?? null;
  const accountId = body.outcome?.account_id ?? null;

  if (!draft || !accountId) {
    return [{ json: { route: 'respond', status: 'invalid', message: 'Missing pending outcome draft or account selection.' } }];
  }

  return [{ json: { route: 'finalize', submittedAt, draft, account_id: accountId } }];
}

const originalMessage = String(body.outcome?.originalMessage ?? '').trim();

if (!originalMessage) {
  return [{ json: { route: 'respond', status: 'invalid', message: 'Outcome originalMessage is required.' } }];
}

return [{
  json: {
    route: 'extract',
    submittedAt,
    originalMessage,
    discordContext: body.discordContext ?? {}
  }
}];

const base = $('Prepare outcome mode').first().json;
const rows = $input.all().map((item) => item.json);
const accountRows = rows.filter((row) => row.account_id && row.account_name);
const categoryRows = rows.filter((row) => row.category_name);

const accountOptions = accountRows.map((row) => ({
  value: String(row.account_id).trim(),
  label: String(row.account_name).trim(),
  description: row.provider ? String(row.provider).trim().slice(0, 100) : undefined
}));

const categoryOptions = categoryRows
  .filter((row) => String(row.active ?? 'TRUE').toLowerCase() !== 'false')
  .map((row) => ({
    value: String(row.category_name).trim(),
    label: String(row.category_name).trim(),
    description: row.parent_category ? `Parent: ${String(row.parent_category).trim()}`.slice(0, 100) : undefined
  }));

return [{
  json: {
    ...base,
    account_options: accountOptions,
    category_options: categoryOptions,
    account_catalog_text: accountOptions.length > 0 ? accountOptions.map((option) => `${option.value}: ${option.label}${option.description ? ` (${option.description})` : ''}`).join('; ') : 'No accounts available',
    category_catalog_text: categoryOptions.length > 0 ? categoryOptions.map((option) => `${option.value}${option.description ? ` (${option.description})` : ''}`).join('; ') : 'No categories available'
  }
}];

