const responseText = $input.first().json.output?.[0]?.content?.[0]?.text;
const base = $('Build outcome catalogs').first().json;

if (!responseText) {
  return [{ json: { route: 'respond', status: 'invalid', message: 'Outcome extraction returned no structured response.' } }];
}

const extracted = JSON.parse(responseText);
const amount = Number(extracted.amount);
const note = String(extracted.note ?? '').trim();
const allowedAccounts = new Set((base.account_options ?? []).map((option) => option.value));
const allowedCategories = new Set((base.category_options ?? []).map((option) => option.value));
const extractedAccountId = extracted.account_id ? String(extracted.account_id).trim() : null;
const extractedCategory = extracted.category ? String(extracted.category).trim() : null;

if (!Number.isFinite(amount) || amount <= 0) {
  return [{ json: { route: 'respond', status: 'invalid', message: 'Could not determine a valid amount from the outcome message.' } }];
}

if (!note) {
  return [{ json: { route: 'respond', status: 'invalid', message: 'Could not determine a description for the outcome message.' } }];
}

const normalizedAccountId = extractedAccountId && allowedAccounts.has(extractedAccountId) ? extractedAccountId : null;
const normalizedCategory = extractedCategory && allowedCategories.has(extractedCategory) ? extractedCategory : '';

const baseTransaction = {
  transaction_id: `txn_${Date.now()}`,
  date_time: base.submittedAt,
  account_id: null,
  amount,
  category: normalizedCategory,
  type: 'expense',
  provider_reference: base.originalMessage,
  receipt_id: '',
  note
};

if (!normalizedAccountId) {
  return [{
    json: {
      route: 'respond',
      status: 'needs_account',
      pending_id: baseTransaction.transaction_id,
      prompt: 'Which account was used for this transaction?',
      draft: baseTransaction,
      account_options: base.account_options,
      warning: normalizedCategory ? '' : 'Category was not confidently matched and was left blank.'
    }
  }];
}

return [{
  json: {
    route: 'write',
    transaction: {
      ...baseTransaction,
      account_id: normalizedAccountId
    },
    warning: normalizedCategory ? '' : 'Category was not confidently matched and was left blank.'
  }
}];

const allowedAccounts = new Set(($json.account_options ?? []).map((option) => option.value));
const draft = $json.draft ?? null;
const accountId = String($json.account_id ?? '').trim();

if (!draft || !accountId) {
  return [{ json: { route: 'respond', status: 'invalid', message: 'Missing draft outcome or account selection.' } }];
}

if (allowedAccounts.size > 0 && !allowedAccounts.has(accountId)) {
  return [{ json: { route: 'respond', status: 'invalid', message: 'Selected account is not supported.' } }];
}

return [{
  json: {
    route: 'write',
    transaction: {
      ...draft,
      account_id: accountId
    },
    warning: draft.category ? '' : 'Category was not confidently matched and was left blank.'
  }
}];

const base = $('Prepare outcome mode').first().json;
const accountRows = $input.all().map((item) => item.json);
const accountOptions = accountRows
  .filter((row) => row.account_id && row.account_name)
  .map((row) => ({
    value: String(row.account_id).trim(),
    label: String(row.account_name).trim(),
    description: row.provider ? String(row.provider).trim().slice(0, 100) : undefined
  }));

return [{
  json: {
    ...base,
    account_options: accountOptions
  }
}];

const transaction = $json.transaction ?? null;

if (!transaction) {
  return [{ json: { route: 'respond', status: 'invalid', message: 'Missing transaction payload before sheet write.' } }];
}

return [{ json: { transaction } }];

