const extracted = JSON.parse($input.first().json.output[0].content[0].text);
const webhook = $("Webhook get receipt image").first().json.body;
const submittedAt = webhook.submittedAt ?? new Date().toISOString();
const receiptId = extracted.order_id ?? `receipt_${Date.now()}`;
const dedupeKey = [extracted.merchant ?? '', extracted.order_id ?? '', extracted.payment?.total_vnd ?? '', extracted.order_time ?? ''].join('|');

return [{
  json: {
    receipt_id: receiptId,
    source_file_id: '',
    merchant: extracted.merchant ?? null,
    order_status: extracted.order_status ?? null,
    order_time: extracted.order_time ?? null,
    total_vnd: extracted.payment?.total_vnd ?? null,
    amount_paid_vnd: extracted.payment?.amount_paid_vnd ?? null,
    amount_due_vnd: extracted.payment?.amount_due_vnd ?? null,
    payment_method: '',
    note: webhook.note ?? '',
    created_at: submittedAt,
    updated_at: submittedAt,
    dedupe_key: dedupeKey,
    items: Array.isArray(extracted.items) ? extracted.items : []
  }
}];

const base = $('Code in JavaScript').first().json;
const drive = $json;

return [{
  json: {
    ...base,
    source_file_id: drive.id ?? '',
    updated_at: new Date().toISOString()
  }
}];

const receipt = $input.first().json;
const items = Array.isArray(receipt.items) ? receipt.items : [];

return items.map((item, index) => ({
  json: {
    item_id: `${receipt.receipt_id}:${index + 1}`,
    receipt_id: receipt.receipt_id,
    item_name: item?.name ?? null,
    quantity: item?.quantity ?? null,
    price_vnd: item?.price_vnd ?? null,
    line_total_vnd: typeof item?.quantity === 'number' && typeof item?.price_vnd === 'number' ? item.quantity * item.price_vnd : null
  }
}));
